export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
  // Cells die from underpopulation with fewer than 2 neighbors (minimum for survival)
  if (liveCells.length < 2) {
    return [];
  }

  // Helper function to count neighbors
  const countNeighbors = (row: number, col: number): number => {
    let count = 0;
    for (let r = row - 1; r <= row + 1; r++) {
      for (let c = col - 1; c <= col + 1; c++) {
        if (r === row && c === col) continue; // Skip the cell itself
        if (liveCells.some(cell => cell[0] === r && cell[1] === c)) {
          count++;
        }
      }
    }
    return count;
  };

  // Keep live cells with 2 or 3 neighbors
  return liveCells.filter(cell => {
    const neighbors = countNeighbors(cell[0], cell[1]);
    return neighbors === 2 || neighbors === 3;
  });
}

